import { callMcpSkill } from "@/lib/ai/skills/mcp";

const TOOL_ID = "294100e8-c648-4e5f-a254-95a14b56e398";

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function getNumeric(value) {
  return typeof value === "number" && Number.isFinite(value) ? value : null;
}

function extractSlippagePercent(whaleCost, key) {
  const bucket = whaleCost && typeof whaleCost === "object" ? whaleCost[key] : null;
  if (!bucket || typeof bucket !== "object") return null;
  const candidates = [
    bucket.slippagePercent,
    bucket.slippage,
    bucket.estimatedSlippagePercent,
    bucket.estimatedSlippage,
    bucket.percent
  ];
  for (const v of candidates) {
    const n = getNumeric(v);
    if (n !== null) return n;
  }
  return null;
}

export async function main() {
  const discovery = await callMcpSkill({
    toolId: TOOL_ID,
    toolName: "find_moderate_probability_bets",
    args: {
      limit: 20,
      sortBy: "liquidity",
      minPrice: 0.4,
      maxPrice: 0.6,
      minLiquidity: 1000000,
      category: "all"
    }
  });

  const opportunities = asArray(discovery?.opportunities).filter((x) => x && typeof x === "object");

  const shortlisted = opportunities.slice(0, 5);

  const liquidityChecks = [];
  for (const opp of shortlisted) {
    const q = opp.conditionId || opp.slug || opp.market || "";
    if (!q) continue;
    const res = await callMcpSkill({
      toolId: TOOL_ID,
      toolName: "analyze_market_liquidity",
      args: opp.conditionId
        ? { conditionId: opp.conditionId }
        : opp.slug
          ? { slug: opp.slug }
          : { marketQuery: opp.market }
    });
    liquidityChecks.push({ opp, res });
  }

  const rows = liquidityChecks.map(({ opp, res }) => {
    const slippage5k = extractSlippagePercent(res?.whaleCost, "sell5k");
    const slippage1k = extractSlippagePercent(res?.whaleCost, "sell1k");
    const slippage10k = extractSlippagePercent(res?.whaleCost, "sell10k");
    const liquidityScore = res?.liquidityScore || null;
    const totalDepthUsd = getNumeric(res?.depth?.totalDepthUsd);
    const bidDepthUsd = getNumeric(res?.depth?.bidDepthUsd);
    const askDepthUsd = getNumeric(res?.depth?.askDepthUsd);

    const tradabilityScore =
      (liquidityScore === "excellent" ? 4 : liquidityScore === "good" ? 3 : liquidityScore === "moderate" ? 2 : liquidityScore === "poor" ? 1 : 0) +
      (slippage5k !== null ? Math.max(0, 3 - slippage5k) : 0) +
      (totalDepthUsd !== null ? Math.min(2, totalDepthUsd / 500000) : 0);

    return {
      market: res?.market || opp.market,
      url: opp.url,
      conditionId: opp.conditionId || res?.conditionId || null,
      tokenId: res?.tokenId || null,
      currentPrice: getNumeric(opp.currentPrice),
      liquidity: getNumeric(opp.liquidity),
      volume24h: getNumeric(opp.volume24h),
      liquidityScore,
      totalDepthUsd,
      bidDepthUsd,
      askDepthUsd,
      slippage1kPercent: slippage1k,
      slippage5kPercent: slippage5k,
      slippage10kPercent: slippage10k,
      whaleRecommendation: res?.recommendation || null,
      tradabilityScore
    };
  });

  rows.sort((a, b) => {
    const aSlip = a.slippage5kPercent;
    const bSlip = b.slippage5kPercent;
    if (aSlip !== null && bSlip !== null && aSlip !== bSlip) return aSlip - bSlip;
    if (a.liquidityScore !== b.liquidityScore) {
      const order = { excellent: 4, good: 3, moderate: 2, poor: 1, illiquid: 0 };
      return (order[b.liquidityScore] || 0) - (order[a.liquidityScore] || 0);
    }
    return (b.tradabilityScore || 0) - (a.tradabilityScore || 0);
  });

  return {
    filters: {
      priceRange: [0.4, 0.6],
      minLiquidity: 1000000,
      category: "all"
    },
    discoverySummary: discovery?.summary || null,
    matchedCount: opportunities.length,
    shortlistedCount: shortlisted.length,
    rankedFor$5000Exit: rows,
    note: "Ranked using live liquidity checks from a past query result in this turn; values reflect the fetched snapshot, not real-time beyond that fetch."
  };
}

