import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const result = await callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "find_arbitrage_opportunities",
    args: {
      category: "politics",
      limit: 20
    }
  });

  const arbitrageOpportunities = Array.isArray(result.arbitrageOpportunities)
    ? result.arbitrageOpportunities
    : [];
  const wideSpreadMarkets = Array.isArray(result.wideSpreadMarkets)
    ? result.wideSpreadMarkets
    : [];

  const passiveOrderCandidates = wideSpreadMarkets
    .filter((m) => typeof m.spread === "number" && m.spread > 0)
    .slice(0, 10)
    .map((m) => ({
      market: m.market,
      url: m.url,
      spread: m.spread,
      midPrice: m.midPrice,
      spreadPercent: m.spreadPercent
    }));

  const arbTable = arbitrageOpportunities.slice(0, 10).map((m) => ({
    market: m.market,
    url: m.url,
    totalCost: m.totalCost,
    buyYesAt: m.buyYesAt,
    buyNoAt: m.buyNoAt,
    potentialEdge: m.potentialEdge,
    edgePercent: m.edgePercent,
    liquidity: m.liquidity
  }));

  const wideTable = wideSpreadMarkets.slice(0, 10).map((m) => ({
    market: m.market,
    url: m.url,
    spread: m.spread,
    midPrice: m.midPrice,
    spreadPercent: m.spreadPercent
  }));

  const summary = result.summary || {};

  return {
    fetchedAt: result.fetchedAt,
    scannedMarkets: result.scannedMarkets,
    summary,
    verifiedArbitrage: arbTable,
    widestSpreads: wideTable,
    passiveOrderCandidates,
    note:
      passiveOrderCandidates.length > 0
        ? "These wide-spread markets may be candidates for passive limit orders, but the tool does not guarantee fills."
        : "No obvious passive-order candidates were returned from the verified wide-spread scan."
  };
}

