import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

const POLYMARKET_TOOL_ID = "294100e8-c648-4e5f-a254-95a14b56e398";

function asNumber(v) {
  return typeof v === "number" && Number.isFinite(v) ? v : null;
}

function sortByPriceDesc(a, b) {
  return (asNumber(b?.currentPrice) ?? -1) - (asNumber(a?.currentPrice) ?? -1);
}

function normalizeOutcomeLabel(row) {
  return String(row?.name || row?.matchedName || row?.requestedName || "");
}

function isCleanlyAbsorbable(liqRow) {
  const s5 = asNumber(liqRow?.slippage5kPercent);
  const s10 = asNumber(liqRow?.slippage10kPercent);
  return s5 !== null && s10 !== null && s5 <= 2 && s10 <= 5;
}

export async function main() {
  // Probe: get a live politics shortlist first, then deterministically select the best multi-outcome event.
  const shortlist = await callMcpSkill({
    toolId: POLYMARKET_TOOL_ID,
    toolName: "get_top_markets",
    args: {
      category: "politics",
      sortBy: "liquidity",
      limit: 20,
    },
  });

  const markets = Array.isArray(shortlist?.markets) ? shortlist.markets : [];
  const rankedCandidates = pickTopSemanticCandidates({
    target: "most liquid live multi-outcome politics event on Polymarket",
    candidates: markets,
    requiredTerms: ["politics"],
    avoidTerms: ["single", "yes/no", "binary"],
    limit: 5,
  });

  const selectedEvent = Array.isArray(rankedCandidates) && rankedCandidates.length > 0 ? rankedCandidates[0] : null;

  if (!selectedEvent?.slug) {
    return {
      missingData: ["selected live politics event"],
      attemptedBranches: [
        "get_top_markets(category=politics, sortBy=liquidity, limit=20)",
        "pickTopSemanticCandidates(target=most liquid live multi-outcome politics event on Polymarket)",
      ],
      stopReason: "No suitable live multi-outcome politics event found in shortlist",
    };
  }

  // Decide: resolve the full event and keep the read batch parallel only across different endpoints.
  const readBatch = await callMcpSkillsParallel({
    label: "polymarket-politics-event-read-batch",
    calls: [
      {
        key: "eventOutcomes",
        toolId: POLYMARKET_TOOL_ID,
        toolName: "get_event_outcomes",
        args: { slug: selectedEvent.slug },
      },
      {
        key: "eventLiquidity",
        toolId: POLYMARKET_TOOL_ID,
        toolName: "analyze_event_outcome_liquidity",
        args: { slug: selectedEvent.slug, limit: 8, sortBy: "volume" },
      },
    ],
  });

  const eventOutcomesEntry = readBatch.results.find((r) => r.key === "eventOutcomes");
  const eventLiquidityEntry = readBatch.results.find((r) => r.key === "eventLiquidity");

  const eventOutcomes = eventOutcomesEntry && eventOutcomesEntry.status === "fulfilled" ? eventOutcomesEntry.value : null;
  const eventLiquidity = eventLiquidityEntry && eventLiquidityEntry.status === "fulfilled" ? eventLiquidityEntry.value : null;

  const outcomes = Array.isArray(eventOutcomes?.outcomes) ? eventOutcomes.outcomes : [];
  const topFourByPrice = [...outcomes].sort(sortByPriceDesc).slice(0, 4);

  // Execute: fetch direct liquidity for the exact top four price leaders using their token IDs if available.
  const outcomeTokenIds = topFourByPrice
    .map((o) => o?.tokenId)
    .filter((tokenId) => typeof tokenId === "string" && tokenId.length > 0);

  const directLiquidityBatch = outcomeTokenIds.length > 0
    ? await callMcpSkillsParallel({
        label: "top-four-direct-liquidity",
        calls: outcomeTokenIds.map((tokenId, idx) => ({
          key: `liq-${idx}`,
          toolId: POLYMARKET_TOOL_ID,
          toolName: "analyze_market_liquidity",
          args: { tokenId },
        })),
      })
    : { results: [], summary: null };

