  }

  if (!selected || (!selected.slug && !selected.conditionId)) {
    return {
      missingData: true,
      attemptedBranches: ["get_top_markets", "semantic_targeting"],
      stopReason: "No suitable live ending-soon market could be selected from discovery results."
    };
  }

  const activity = await callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "summarize_live_market_activity",
