      conditionId: selected.conditionId,
      slug: selected.slug,
      tradeLimit: 20,
      sortBy: "ending_soon",
      endingWithinDays: 7
    }
  });

  const tradesSummary = activity?.tradesSummary || {};
  const recentTrades = Array.isArray(activity?.recentTrades) ? activity.recentTrades : [];
  const openInterest = activity?.openInterest || {};
  const market = activity?.selectedMarket || selected;

  const totalTrades = tradesSummary.totalTrades ?? 0;
  const totalVolume = tradesSummary.totalVolume ?? 0;
  const buyVolume = tradesSummary.buyVolume ?? 0;
  const sellVolume = tradesSummary.sellVolume ?? 0;

  const imbalance = totalVolume > 0 ? Math.abs((buyVolume - sellVolume) / totalVolume) : null;
  const activityIntensity = totalTrades >= 10 || totalVolume >= 1000;

  let read = "noise";
  let rationale = "Activity is too thin or balanced to support a strong conviction read.";
  if (activityIntensity && imbalance !== null && imbalance >= 0.2) {
    read = "genuine conviction";
