import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const result = await callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "find_trading_opportunities",
    args: {
      depth: "medium",
      category: "politics",
      strategy: "high_confidence",
      minLiquidity: 5000
    }
  });

  const opportunities = Array.isArray(result?.opportunities) ? result.opportunities : [];

  const scored = opportunities.map((op) => {
    const liquidity = typeof op?.liquidity === "number" ? op.liquidity : 0;
    const price = typeof op?.currentPrice === "number" ? op.currentPrice : null;
    const confidence = op?.confidence || "low";

    let confidenceScore = 0;
    if (confidence === "high") confidenceScore = 3;
    else if (confidence === "medium") confidenceScore = 2;
    else if (confidence === "low") confidenceScore = 1;

    const priceCenterBonus = price === null ? 0 : Math.max(0, 1 - Math.abs(price - 0.8) * 4);
    const liquidityScore = Math.log10(Math.max(liquidity, 1));
    const cleanThesisScore = liquidityScore * 2 + confidenceScore * 3 + priceCenterBonus;

    return {
      market: op?.market,
      url: op?.url,
      slug: op?.slug,
      conditionId: op?.conditionId,
      currentPrice: op?.currentPrice,
      liquidity: op?.liquidity,
      volume24h: op?.volume24h,
      confidence: op?.confidence,
      suggestedSide: op?.suggestedSide,
      opportunityType: op?.opportunityType,
      impliedProbability: op?.impliedProbability,
      whyThisOpportunity: op?.whyThisOpportunity,
      riskFactors: op?.riskFactors,
      cleanThesisScore
    };
  });

  scored.sort((a, b) => b.cleanThesisScore - a.cleanThesisScore);

  return {
    summary: result?.summary,
    fetchedAt: result?.fetchedAt,
    showing: `${scored.length} matching markets`,
    rankingMethod: "cleanThesisScore = liquidity + confidence + price stability bias",
    markets: scored.slice(0, 10),
    nearestMatches: Array.isArray(result?.nearestMatches) ? result.nearestMatches : undefined,
    noOpportunitiesReason: result?.noOpportunitiesReason
  };
}

import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const result = await callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "find_trading_opportunities",
    args: {
      depth: "medium",
      category: "politics",
      strategy: "high_confidence",
      minLiquidity: 5000
    }
  });

  const opportunities = Array.isArray(result?.opportunities) ? result.opportunities : [];
  const political = opportunities.filter((op) => {
    const text = `${op?.market || ""} ${op?.slug || ""} ${op?.url || ""}`.toLowerCase();
    return /(iran|presidential|election|nomination|ceasefire|forces enter|regime|gavin newsom|jd vance)/.test(text);
  });

  const scored = political.map((op) => {
    const liquidity = typeof op?.liquidity === "number" ? op.liquidity : 0;
    const price = typeof op?.currentPrice === "number" ? op.currentPrice : null;
    const confidence = op?.confidence || "low";

    let confidenceScore = 0;
    if (confidence === "high") confidenceScore = 3;
    else if (confidence === "medium") confidenceScore = 2;
    else if (confidence === "low") confidenceScore = 1;

    const priceCenterBonus = price === null ? 0 : Math.max(0, 1 - Math.abs(price - 0.8) * 4);
    const liquidityScore = Math.log10(Math.max(liquidity, 1));
    const spreadBps = typeof op?.spreadBps === "number" ? op.spreadBps : (typeof op?.spread === "number" ? op.spread : null);
    const spreadPenalty = spreadBps === null ? 0 : Math.min(3, spreadBps / 100);
    const cleanThesisScore = liquidityScore * 2 + confidenceScore * 3 + priceCenterBonus - spreadPenalty;

    return {
      market: op?.market,
      url: op?.url,
      slug: op?.slug,
      conditionId: op?.conditionId,
      currentPrice: op?.currentPrice,
      liquidity: op?.liquidity,
      volume24h: op?.volume24h,
      confidence: op?.confidence,
      suggestedSide: op?.suggestedSide,
      opportunityType: op?.opportunityType,
      impliedProbability: op?.impliedProbability,
      whyThisOpportunity: op?.whyThisOpportunity,
      riskFactors: op?.riskFactors,
      cleanThesisScore,
      spreadBps
    };
  });

  const topForChecks = scored.slice(0, 3);
  const liquidityChecks = await Promise.all(topForChecks.map((op) => callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "analyze_market_liquidity",
    args: { slug: op.slug }
  })));
  const efficiencyChecks = await Promise.all(topForChecks.map((op) => callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "check_market_efficiency",
    args: { slug: op.slug }
  })));

  const enriched = scored.map((op) => {
    const liq = liquidityChecks.find((x) => x?.slug === op.slug || x?.market === op.market);
    const eff = efficiencyChecks.find((x) => x?.conditionId === op.conditionId || x?.market === op.market);
    return {
      ...op,
      spread: liq?.spread,
      liquidityAnalysis: liq,
      efficiency: eff?.marketEfficiency,
      cleanThesisScore: op.cleanThesisScore - ((liq?.spread?.bps || 0) / 1000) - ((eff?.marketEfficiency?.vigBps || 0) / 10000)
    };
  });

  enriched.sort((a, b) => b.cleanThesisScore - a.cleanThesisScore);

  return {
    summary: result?.summary,
    fetchedAt: result?.fetchedAt,
    showing: `${scored.length} matching markets`,
    rankingMethod: "cleanThesisScore = liquidity + confidence + price stability bias",
    markets: scored.slice(0, 10),
    nearestMatches: Array.isArray(result?.nearestMatches) ? result.nearestMatches : undefined,
    noOpportunitiesReason: result?.noOpportunitiesReason
  };
}

